#!/usr/bin/env python3
import argparse
import os
import re
import sys
from pathlib import Path

def search_files(directory: str, pattern: str, regex: bool = False, recursive: bool = True) -> list[Path]:
    """Search for files matching a pattern in a directory."""
    results = []
    root = Path(directory)
    if not root.exists():
        raise FileNotFoundError(f"Directory not found: {directory}")

    globber = root.rglob if recursive else root.glob
    for path in globber("*"):
        if path.is_file():
            if regex:
                if re.search(pattern, path.name):
                    results.append(path)
            else:
                if pattern in path.name:
                    results.append(path)
    return results

def search_content(directory: str, pattern: str, regex: bool = False, recursive: bool = True) -> list[tuple[Path, int, str]]:
    """Search for files containing text matching a pattern."""
    results = []
    root = Path(directory)
    if not root.exists():
        raise FileNotFoundError(f"Directory not found: {directory}")

    globber = root.rglob if recursive else root.glob
    for path in globber("*"):
        if not path.is_file():
            continue
        try:
            content = path.read_text(errors="ignore")
            if regex:
                for i, line in enumerate(content.split("\n"), 1):
                    if re.search(pattern, line):
                        results.append((path, i, line.strip()))
            else:
                if pattern in content:
                    for i, line in enumerate(content.split("\n"), 1):
                        if pattern in line:
                            results.append((path, i, line.strip()))
        except Exception:
            continue
    return results

def main():
    parser = argparse.ArgumentParser(description="Search files by name or content")
    parser.add_argument("directory", help="Directory to search in")
    parser.add_argument("pattern", help="Search pattern")
    parser.add_argument("-r", "--regex", action="store_true", help="Use regex pattern")
    parser.add_argument("-c", "--content", action="store_true", help="Search file content instead of names")
    parser.add_argument("--no-recursive", action="store_true", help="Don't search subdirectories")

    args = parser.parse_args()
    recursive = not args.no_recursive

    if args.content:
        results = search_content(args.directory, args.pattern, args.regex, recursive)
        for path, line_num, text in results[:50]:
            print(f"{path}:{line_num}: {text}")
    else:
        results = search_files(args.directory, args.pattern, args.regex, recursive)
        for path in results[:50]:
            print(str(path))

    print(f"\nFound {len(results)} result(s)")

if __name__ == "__main__":
    main()

